export default function ServiceCard({
  title,
  iconLabel,
  svg,
}: ServiceCardProps) {
  return (
    <div className="flex h-full flex-col items-start gap-4 p-5 ml-5">
      <div className="shrink-0">
        <ServiceIcon type={iconLabel} svg={svg} />
      </div>

      {/* Title */}
      <h4
        className={`${poppins.className} text-[26px] leading-[30px] tracking-[0em] font-bold text-[#1E1E1F] mt-2`}
      >
        {title}
      </h4>

      {/* Arrow Link */}
      <button
        aria-label={`Learn more about ${title}`}
        className="mt-auto"
      >
        <ArrowIcon />
      </button>
    </div>
  );
}
